 {"id":"asupersync-5eq","title":"[Time] Implement Interval Timers","description":"# Interval Timers

## Overview
Repeating timers with configurable behavior for missed ticks.

## Implementation Steps

### Step 1: Interval Type
```rust
use std::time::{Duration, Instant};
use std::pin::Pin;
use std::task::{Context, Poll};

/// Repeating interval timer
pub struct Interval {
    /// Next tick deadline
    deadline: Instant,
    /// Period between ticks
    period: Duration,
    /// Behavior for missed ticks
    missed_tick_behavior: MissedTickBehavior,
}

impl Interval {
    fn new(start: Instant, period: Duration) -> Self {
        Self {
            deadline: start,
            period,
            missed_tick_behavior: MissedTickBehavior::default(),
        }
    }

    /// Wait for next tick
    pub async fn tick(&mut self) -> Instant {
        // Fast path: deadline already passed
        let now = Instant::now();
        if self.deadline <= now {
            let tick_instant = self.deadline;
            self.advance_deadline(now);
            return tick_instant;
        }

        // Wait until deadline
        sleep_until(self.deadline).await;
        let tick_instant = self.deadline;
        self.advance_deadline(Instant::now());
        tick_instant
    }

    /// Get the period
    pub fn period(&self) -> Duration {
        self.period
    }

    /// Set missed tick behavior
    pub fn set_missed_tick_behavior(&mut self, behavior: MissedTickBehavior) {
        self.missed_tick_behavior = behavior;
    }

    /// Reset interval to start from now
    pub fn reset(&mut self) {
        self.deadline = Instant::now() + self.period;
    }

    /// Reset interval starting at specific instant
    pub fn reset_at(&mut self, instant: Instant) {
        self.deadline = instant;
    }

    /// Reset interval after specific delay from now
    pub fn reset_after(&mut self, after: Duration) {
        self.deadline = Instant::now() + after;
    }

    fn advance_deadline(&mut self, now: Instant) {
        match self.missed_tick_behavior {
            MissedTickBehavior::Burst => {
                // Just add one period (caller handles bursting)
                self.deadline += self.period;
            }
            MissedTickBehavior::Delay => {
                // Next tick is period from now
                self.deadline = now + self.period;
            }
            MissedTickBehavior::Skip => {
                // Skip to next aligned tick
                let elapsed = now - self.deadline;
                let periods = (elapsed.as_nanos() / self.period.as_nanos()) as u32 + 1;
                self.deadline += self.period * periods;
            }
        }
    }
}

impl Stream for Interval {
    type Item = Instant;

    fn poll_next(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Option<Instant>> {
        let this = self.get_mut();

        let now = Instant::now();
        if this.deadline <= now {
            let tick = this.deadline;
            this.advance_deadline(now);
            return Poll::Ready(Some(tick));
        }

        // Register wake for deadline
        // ...
        Poll::Pending
    }
}
```

### Step 2: Missed Tick Behavior
```rust
/// How to handle missed ticks
#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
pub enum MissedTickBehavior {
    /// Fire immediately for each missed tick (catch up)
    #[default]
    Burst,
    /// Delay next tick to be period from now
    Delay,
    /// Skip missed ticks, fire at next aligned time
    Skip,
}

impl MissedTickBehavior {
    /// Burst mode: Fire all missed ticks as fast as possible
    pub const fn burst() -> Self { Self::Burst }

    /// Delay mode: Reset timer after each tick
    pub const fn delay() -> Self { Self::Delay }

    /// Skip mode: Skip to next aligned tick
    pub const fn skip() -> Self { Self::Skip }
}
```

### Step 3: Constructor Functions
```rust
/// Create interval timer starting now
pub fn interval(period: Duration) -> Interval {
    interval_at(Instant::now(), period)
}

/// Create interval timer starting at specific instant
pub fn interval_at(start: Instant, period: Duration) -> Interval {
    assert!(period > Duration::ZERO, "interval period must be > 0");
    Interval::new(start, period)
}
```

### Step 4: IntervalStream Wrapper
```rust
/// Stream that yields at regular intervals
pub struct IntervalStream {
    inner: Interval,
}

impl IntervalStream {
    pub fn new(interval: Interval) -> Self {
        Self { inner: interval }
    }
}

impl Stream for IntervalStream {
    type Item = Instant;

    fn poll_next(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Option<Instant>> {
        Pin::new(&mut self.inner).poll_next(cx)
    }
}
```

## Cancel-Safety
- tick(): cancel-safe, next call will return the next tick
- Stream::poll_next: cancel-safe
- Missed ticks handled per configured behavior

